create extension if not exists pgcrypto;
create table public.projects (id uuid primary key default gen_random_uuid(), name text not null, objective text, starts_on date, estimated_ends_on date, description text, next_meeting_on date, teams_url text, created_at timestamptz not null default now());
create table public.members (id uuid primary key default gen_random_uuid(), project_id uuid not null references public.projects(id), user_id uuid unique references auth.users(id), name text not null, email text not null, active boolean not null default true, created_at timestamptz not null default now());
create table public.products (id uuid primary key default gen_random_uuid(), project_id uuid not null references public.projects(id), name text not null, committed_on date, teams_url text, archived_at timestamptz, created_at timestamptz not null default now());
create type public.task_type as enum ('execution','quality_control','milestone'); create type public.task_status as enum ('pending','in_progress','done'); create type public.task_priority as enum ('high','medium','low');
create table public.tasks (id uuid primary key default gen_random_uuid(), project_id uuid not null references public.projects(id), title text not null, description text, type public.task_type not null default 'execution', product_id uuid references public.products(id), owner_id uuid references public.members(id), collaborators uuid[] not null default '{}', priority public.task_priority not null default 'medium', status public.task_status not null default 'pending', planned_start date, planned_end date, adjusted_start date, adjusted_end date, completed_on date, depends_on_id uuid references public.tasks(id), reviewed_task_id uuid references public.tasks(id), risk text, comment text, teams_url text, archived_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), check ((type <> 'milestone') or planned_start = planned_end));
create table public.meetings (id uuid primary key default gen_random_uuid(), project_id uuid not null references public.projects(id), held_on date not null, participants uuid[] not null default '{}', minutes_url text not null, recording_url text, archived_at timestamptz, created_at timestamptz not null default now());
create table public.audit_log (id bigint generated always as identity primary key, project_id uuid not null references public.projects(id), actor_id uuid references auth.users(id), entity_type text not null, entity_id uuid not null, action text not null, old_value jsonb, new_value jsonb, occurred_at timestamptz not null default now());
create or replace function public.audit_row() returns trigger language plpgsql security definer set search_path=public as $$ begin if tg_op='DELETE' then insert into audit_log(project_id,actor_id,entity_type,entity_id,action,old_value) values (old.project_id,auth.uid(),tg_table_name,old.id,tg_op,to_jsonb(old)); return old; else insert into audit_log(project_id,actor_id,entity_type,entity_id,action,old_value,new_value) values (new.project_id,auth.uid(),tg_table_name,new.id,tg_op,to_jsonb(old),to_jsonb(new)); return new; end if; end $$;
create or replace function public.task_dates() returns trigger language plpgsql as $$ begin if new.status='done' and old.status is distinct from 'done' and new.completed_on is null then new.completed_on=current_date; end if new.planned_start is null then raise exception 'Las fechas programadas son obligatorias'; end if tg_op='UPDATE' and new.planned_start is distinct from old.planned_start then raise exception 'La línea base no se modifica; use fechas ajustadas'; end if new.type='milestone' then new.planned_end=new.planned_start; end if; new.updated_at=now(); return new; end $$;
create trigger tasks_dates before insert or update on public.tasks for each row execute function task_dates();
create trigger tasks_audit after insert or update or delete on public.tasks for each row execute function audit_row(); create trigger products_audit after insert or update or delete on public.products for each row execute function audit_row(); create trigger meetings_audit after insert or update or delete on public.meetings for each row execute function audit_row();
alter table public.projects enable row level security; alter table public.members enable row level security; alter table public.products enable row level security; alter table public.tasks enable row level security; alter table public.meetings enable row level security; alter table public.audit_log enable row level security;
create or replace function public.is_member(pid uuid) returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from members where project_id=pid and user_id=auth.uid() and active)$$;
create policy "miembros consultan proyecto" on projects for select using (is_member(id)); create policy "miembros actualizan proyecto" on projects for update using (is_member(id));
create policy "miembros gestionan integrantes" on members for all using (is_member(project_id)) with check (is_member(project_id)); create policy "miembros gestionan productos" on products for all using (is_member(project_id)) with check (is_member(project_id)); create policy "miembros gestionan tareas" on tasks for all using (is_member(project_id)) with check (is_member(project_id)); create policy "miembros gestionan reuniones" on meetings for all using (is_member(project_id)) with check (is_member(project_id)); create policy "miembros ven auditoría" on audit_log for select using (is_member(project_id));
